#include <stdio.h>

struct Student {
    int rollno;
    char name[50];
    float marks;
};

int main() {
    // Declare structure variable
    struct Student s1;

    // Assign values to members
    s1.rollno = 101;
    strcpy(s1.name, "John");
    s1.marks = 85.5;

    // Display values
    printf("Roll No: %d\n", s1.rollno);
    printf("Name: %s\n", s1.name);
    printf("Marks: %.2f\n", s1.marks);

    return 0;
}

#include <stdio.h>

struct Employee {
    int id;
    char name[30];
    float salary;
};

int main() {
    // Method 1: Initialize at declaration
    struct Employee e1 = {101, "Alice", 50000.0};

    // Method 2: Partial initialization (remaining = 0)
    struct Employee e2 = {102, "Bob"};

    // Method 3: Designated initialization (C99)
    struct Employee e3 = {.name = "Charlie", .salary = 55000.0, .id = 103};

    printf("Employee 1: %d, %s, %.2f\n", e1.id, e1.name, e1.salary);
    printf("Employee 2: %d, %s, %.2f\n", e2.id, e2.name, e2.salary);
    printf("Employee 3: %d, %s, %.2f\n", e3.id, e3.name, e3.salary);

    return 0;
}

#include <stdio.h>

struct Student {
    int rollno;
    char name[50];
    float marks;
};

int main() {
    struct Student students[3];
    int n = 3;

    // Input data for 3 students
    for(int i = 0; i < n; i++) {
        printf("Enter details for student %d:\n", i+1);
        printf("Roll No: ");
        scanf("%d", &students[i].rollno);
        printf("Name: ");
        scanf("%s", students[i].name);
        printf("Marks: ");
        scanf("%f", &students[i].marks);
    }

    // Display all student records
    printf("\nStudent Records:\n");
    for(int i = 0; i < n; i++) {
        printf("Roll No: %d, Name: %s, Marks: %.2f\n",
               students[i].rollno, students[i].name, students[i].marks);
    }

    return 0;
}

#include <stdio.h>
#include <string.h>

struct Book {
    int bookid;
    char title[50];
    float price;
};

int main() {
    struct Book b1 = {201, "C Programming", 299.99};

    // Declare pointer to structure
    struct Book *ptr;

    // Assign address of structure to pointer
    ptr = &b1;

    // Method 1: Using arrow operator (preferred)
    printf("Using Arrow Operator:\n");
    printf("Book ID: %d\n", ptr->bookid);
    printf("Title: %s\n", ptr->title);
    printf("Price: %.2f\n", ptr->price);

    // Method 2: Using dereferencing (equivalent)
    printf("\nUsing (*ptr).member:\n");
    printf("Book ID: %d\n", (*ptr).bookid);
    printf("Title: %s\n", (*ptr).title);
    printf("Price: %.2f\n", (*ptr).price);

    return 0;
}
